mapper.select:
SELECT b.*, u.username FROM bill b LEFT JOIN `user` u ON b.user_id = u.id
AND b.bill_no LIKE CONCAT('%', #{billNo}, '%')
AND b.order_no LIKE CONCAT('%', #{orderNo}, '%')
AND b.bill_type = #{billType}
AND b.bill_status = #{billStatus}
ORDER BY b.create_time DESC

mapper.update:
UPDATE bill
bill_status = #{billStatus}, remark = #{remark},
WHERE id = #{id}
